import { type CSSProperties } from 'react';

export interface DramsEmptyStateProps {
  icon?: string;
  title: string;
  message?: string;
  actionLabel?: string;
  onAction?: () => void;
  style?: CSSProperties;
  className?: string;
}

// DRAMS design pattern for empty states
// Clean, minimal presentation with centered content

const CONTAINER_STYLE: CSSProperties = {
  textAlign: 'center',
  padding: '60px 20px',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  gap: '16px',
};

const ICON_STYLE: CSSProperties = {
  fontSize: '48px',
  marginBottom: '8px',
};

const TITLE_STYLE: CSSProperties = {
  fontSize: '20px',
  fontWeight: '500',
  color: '#333',
  margin: 0,
};

const MESSAGE_STYLE: CSSProperties = {
  fontSize: '15px',
  color: '#999',
  margin: 0,
  maxWidth: '300px',
};

const ACTION_BUTTON_STYLE: CSSProperties = {
  marginTop: '16px',
  padding: '12px 24px',
  border: 'none',
  borderRadius: '48px',
  background: 'rgb(255, 97, 26)',
  color: 'white',
  fontSize: '15px',
  fontWeight: '500',
  cursor: 'pointer',
  transition: 'transform 0.2s ease',
};

export function DramsEmptyState({
  icon = '🔍',
  title,
  message,
  actionLabel,
  onAction,
  style,
  className,
}: DramsEmptyStateProps): JSX.Element {
  return (
    <div style={{ ...CONTAINER_STYLE, ...style }} className={className}>
      {icon && <div style={ICON_STYLE}>{icon}</div>}
      <h3 style={TITLE_STYLE}>{title}</h3>
      {message && <p style={MESSAGE_STYLE}>{message}</p>}
      {actionLabel && onAction && (
        <button
          type="button"
          onClick={onAction}
          style={ACTION_BUTTON_STYLE}
        >
          {actionLabel}
        </button>
      )}
    </div>
  );
}
