import { type CSSProperties } from 'react';

export interface DramsTabOption {
  value: string;
  label: string;
  count?: number;
  disabled?: boolean;
}

export interface DramsTabGroupProps {
  options: DramsTabOption[];
  value: string;
  onChange: (value: string) => void;
  style?: CSSProperties;
  className?: string;
}

// Reference: /Users/gurusharan/Documents/remote-claude/Research/drams-design/rolling-search.html
// Lines 774-827: Radio Group pattern (also used for tabs)

const TAB_GROUP_STYLE: CSSProperties = {
  display: 'flex',
  gap: '12px',
  flexWrap: 'wrap',
};

const TAB_BUTTON_STYLE: CSSProperties = {
  padding: '12px 20px',
  border: 'none',
  borderRadius: '48px',
  background: 'rgb(238, 238, 238)',
  color: '#333',
  fontSize: '14px',
  fontWeight: '500',
  cursor: 'pointer',
  transition: 'all 0.3s ease',
  textTransform: 'capitalize',
  whiteSpace: 'nowrap',
};

const TAB_BUTTON_ACTIVE_STYLE: CSSProperties = {
  background: 'rgb(255, 97, 26)',
  color: 'white',
};

const TAB_COUNT_STYLE: CSSProperties = {
  marginLeft: '8px',
  opacity: 0.7,
  fontSize: '12px',
};

const TAB_DISABLED_STYLE: CSSProperties = {
  opacity: 0.5,
  cursor: 'not-allowed',
};

export function DramsTabGroup({
  options,
  value,
  onChange,
  style,
  className,
}: DramsTabGroupProps): JSX.Element {
  return (
    <div style={{ ...TAB_GROUP_STYLE, ...style }} className={className}>
      {options.map((option) => {
        const isActive = value === option.value;
        const isDisabled = option.disabled ?? false;

        return (
          <button
            key={option.value}
            type="button"
            onClick={() => !isDisabled && onChange(option.value)}
            disabled={isDisabled}
            style={{
              ...TAB_BUTTON_STYLE,
              ...(isActive ? TAB_BUTTON_ACTIVE_STYLE : {}),
              ...(isDisabled ? TAB_DISABLED_STYLE : {}),
            }}
          >
            {option.label}
            {option.count !== undefined && (
              <span style={TAB_COUNT_STYLE}>({option.count})</span>
            )}
          </button>
        );
      })}
    </div>
  );
}
