import { type CSSProperties } from 'react';

export interface DramsSpinnerProps {
  size?: 'sm' | 'md' | 'lg';
  message?: string;
  style?: CSSProperties;
  className?: string;
}

// DRAMS design pattern for loading spinner
// Orange accent with gray track, smooth rotation

const SIZES = {
  sm: { spinner: 24, track: '3px' },
  md: { spinner: 40, track: '4px' },
  lg: { spinner: 56, track: '5px' },
} as const;

const CONTAINER_STYLE: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '16px',
  padding: '40px 20px',
};

const SPINNER_BASE_STYLE: CSSProperties = {
  borderRadius: '50%',
  animation: 'drams-spin 1s linear infinite',
};

const MESSAGE_STYLE: CSSProperties = {
  fontSize: '15px',
  color: '#999',
  margin: 0,
};

const KEYFRAMES_STYLE = `
  @keyframes drams-spin {
    to { transform: rotate(360deg); }
  }
`;

export function DramsSpinner({
  size = 'md',
  message,
  style,
  className,
}: DramsSpinnerProps): JSX.Element {
  const { spinner: diameter, track } = SIZES[size];

  const spinnerStyle: CSSProperties = {
    ...SPINNER_BASE_STYLE,
    width: diameter,
    height: diameter,
    border: `${track} solid rgb(238, 238, 238)`,
    borderTopColor: 'rgb(255, 97, 26)',
    ...style,
  };

  return (
    <>
      <style>{KEYFRAMES_STYLE}</style>
      <div style={CONTAINER_STYLE} className={className}>
        <div style={spinnerStyle} />
        {message && <p style={MESSAGE_STYLE}>{message}</p>}
      </div>
    </>
  );
}
