import { type CSSProperties } from 'react';

export interface DramsRadioOption {
  value: string;
  label: string;
  description?: string;
  disabled?: boolean;
}

export interface DramsRadioGroupProps {
  name: string;
  options: DramsRadioOption[];
  value: string;
  onChange: (value: string) => void;
  style?: CSSProperties;
  className?: string;
}

// Reference: /Users/gurusharan/Documents/remote-claude/Research/drams-design/rolling-search.html
// Lines 774-827: Radio Group pattern

const RADIO_GROUP_STYLE: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '12px',
};

const RADIO_OPTION_STYLE: CSSProperties = {
  position: 'relative',
};

const RADIO_LABEL_STYLE: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  padding: '12px 18px',
  background: 'rgb(238, 238, 238)',
  borderRadius: '48px',
  cursor: 'pointer',
  transition: 'all 0.3s ease',
};

const RADIO_LABEL_SELECTED_STYLE: CSSProperties = {
  background: 'rgb(255, 97, 26)',
  color: 'white',
};

const RADIO_LABEL_DISABLED_STYLE: CSSProperties = {
  opacity: 0.5,
  cursor: 'not-allowed',
};

const RADIO_DOT_STYLE: CSSProperties = {
  width: '16px',
  height: '16px',
  borderRadius: '50%',
  border: '2px solid #999',
  transition: 'all 0.3s ease',
  flexShrink: 0,
};

const RADIO_DOT_SELECTED_STYLE: CSSProperties = {
  border: '2px solid white',
  background: 'white',
};

const RADIO_TEXT_STYLE: CSSProperties = {
  fontSize: '14px',
  fontWeight: '500',
};

const RADIO_DESC_STYLE: CSSProperties = {
  fontSize: '12px',
  opacity: 0.8,
};

const RADIO_CONTENT_STYLE: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '2px',
  flex: 1,
};

export function DramsRadioGroup({
  name,
  options,
  value,
  onChange,
  style,
  className,
}: DramsRadioGroupProps): JSX.Element {
  return (
    <div style={{ ...RADIO_GROUP_STYLE, ...style }} className={className}>
      {options.map((option) => {
        const isSelected = value === option.value;

        return (
          <div key={option.value} style={RADIO_OPTION_STYLE}>
            <input
              type="radio"
              name={name}
              value={option.value}
              checked={isSelected}
              onChange={() => !option.disabled && onChange(option.value)}
              disabled={option.disabled}
              style={{
                position: 'absolute',
                opacity: 0,
                pointerEvents: 'none',
              }}
            />
            <label
              htmlFor={`${name}-${option.value}`}
              style={{
                ...RADIO_LABEL_STYLE,
                ...(isSelected ? RADIO_LABEL_SELECTED_STYLE : {}),
                ...(option.disabled ? RADIO_LABEL_DISABLED_STYLE : {}),
              }}
            >
              <div
                style={{
                  ...RADIO_DOT_STYLE,
                  ...(isSelected ? RADIO_DOT_SELECTED_STYLE : {}),
                }}
              />
              <div style={RADIO_CONTENT_STYLE}>
                <span style={RADIO_TEXT_STYLE}>{option.label}</span>
                {option.description && (
                  <span style={RADIO_DESC_STYLE}>{option.description}</span>
                )}
              </div>
            </label>
          </div>
        );
      })}
    </div>
  );
}
